1	/**
2	 * Capture Script
3	 *
4	 * Queries `gateway_webhook_deliveries` for real webhook payloads,
5	 * sanitizes PII, and writes one fixture file per {eventType}.{action}.json.
6	 *
7	 * Usage:
8	 *   cd packages/webhook-schemas && pnpm capture
9	 */
10	
11	import { db } from "@db/app/client";
12	import { gatewayWebhookDeliveries } from "@db/app/schema";
13	import { writeFileSync, mkdirSync } from "node:fs";
14	import { join } from "node:path";
15	import { and, isNotNull, sql } from "drizzle-orm";
16	
17	// ── Types ───────────────────────────────────────────────────────────────────
18	
19	type JsonValue =
20	  | string
21	  | number
22	  | boolean
23	  | null
24	  | JsonValue[]
25	  | { [key: string]: JsonValue };
26	
27	// ── PII Sanitization ────────────────────────────────────────────────────────
28	
29	const AUTHOR_CONTEXT_KEYS = new Set([
30	  "author",
31	  "committer",
32	  "co-authored-by",
33	]);
34	
35	function isAuthorContext(key: string): boolean {
36	  const lower = key.toLowerCase();
37	  return AUTHOR_CONTEXT_KEYS.has(lower);
38	}
39	
40	function walk(
41	  obj: Record<string, JsonValue>,
42	  parentKey: string = ""
43	): Record<string, JsonValue> {
44	  for (const [key, value] of Object.entries(obj)) {
45	    if (key === "avatar_url" && typeof value === "string") {
46	      obj[key] = "https://avatars.githubusercontent.com/u/0";
47	      continue;
48	    }
49	
50	    if (key === "email" && typeof value === "string") {
51	      obj[key] = "redacted@example.com";
52	      continue;
53	    }
54	
55	    if (
56	      key === "name" &&
57	      typeof value === "string" &&
58	      isAuthorContext(parentKey)
59	    ) {
60	      obj[key] = "Redacted User";
61	      continue;
62	    }
63	
64	    // Vercel meta field
65	    if (key === "githubCommitAuthorName" && typeof value === "string") {
66	      obj[key] = "Redacted User";
67	      continue;
68	    }
69	
70	    if (value !== null && typeof value === "object" && !Array.isArray(value)) {
71	      walk(value as Record<string, JsonValue>, key);
72	    } else if (Array.isArray(value)) {
73	      for (const item of value) {
74	        if (item !== null && typeof item === "object" && !Array.isArray(item)) {
75	          walk(item as Record<string, JsonValue>, key);
76	        }
77	      }
78	    }
79	  }
80	  return obj;
81	}
82	
83	function sanitize(payload: Record<string, JsonValue>): Record<string, JsonValue> {
84	  const clone = structuredClone(payload);
85	  return walk(clone);
86	}
87	
88	// ── Derive action from payload ──────────────────────────────────────────────
89	
90	function deriveAction(
91	  provider: string,
92	  eventType: string,
93	  payload: Record<string, JsonValue>
94	): string {
95	  if (provider === "github") {
96	    const action = payload.action;
97	    if (typeof action === "string") {
98	      return `${eventType}.${action}`;
99	    }
100	    return eventType;
101	  }
102	
103	  if (provider === "vercel") {
104	    // eventType is already like "deployment.created"
105	    return eventType;
106	  }
107	
108	  return eventType;
109	}
110	
111	// ── Main ────────────────────────────────────────────────────────────────────
112	
113	async function main() {
114	  console.log("Querying gateway_webhook_deliveries...\n");
115	
116	  const rows = await db
117	    .select({
118	      provider: gatewayWebhookDeliveries.provider,
119	      eventType: gatewayWebhookDeliveries.eventType,
120	      payload: gatewayWebhookDeliveries.payload,
121	      receivedAt: gatewayWebhookDeliveries.receivedAt,
122	    })
123	    .from(gatewayWebhookDeliveries)
124	    .where(
125	      and(
126	        isNotNull(gatewayWebhookDeliveries.payload),
127	        sql`${gatewayWebhookDeliveries.provider} IN ('github', 'vercel')`
128	      )
129	    )
130	    .orderBy(gatewayWebhookDeliveries.receivedAt)
131	    .limit(100);
132	
133	  console.log(`Found ${rows.length} rows with payloads\n`);
134	
135	  // Group by provider + action, keep first (oldest) per group
136	  const grouped = new Map<string, Record<string, JsonValue>>();
137	  const providerCounts: Record<string, number> = {};
138	
139	  for (const row of rows) {
140	    if (!row.payload) continue;
141	
142	    let parsed: Record<string, JsonValue>;
143	    try {
144	      parsed = JSON.parse(row.payload) as Record<string, JsonValue>;
145	    } catch {
146	      console.log(`  Skipping unparseable payload for ${row.provider}/${row.eventType}`);
147	      continue;
148	    }
149	
150	    const action = deriveAction(row.provider, row.eventType, parsed);
151	    const key = `${row.provider}:${action}`;
152	
153	    if (!grouped.has(key)) {
154	      grouped.set(key, sanitize(parsed));
155	      providerCounts[row.provider] = (providerCounts[row.provider] ?? 0) + 1;
156	    }
157	  }
158	
159	  // Write fixtures
160	  const fixturesDir = join(import.meta.dirname, "..", "fixtures");
161	
162	  for (const [key, payload] of grouped) {
163	    const colonIdx = key.indexOf(":");
164	    const provider = key.slice(0, colonIdx);
165	    const eventAction = key.slice(colonIdx + 1);
166	
167	    const dir = join(fixturesDir, provider);
168	    mkdirSync(dir, { recursive: true });
169	
170	    const filePath = join(dir, `${eventAction}.json`);
171	    writeFileSync(filePath, JSON.stringify(payload, null, 2) + "\n");
172	  }
173	
174	  // Summary
175	  console.log("Fixtures written:");
176	  for (const [provider, count] of Object.entries(providerCounts)) {
177	    console.log(`  ${provider}: ${count} fixture(s)`);
178	  }
179	  console.log(`\nTotal: ${grouped.size} fixture file(s)`);
180	
181	  // List all written files
182	  console.log("\nFiles:");
183	  for (const key of grouped.keys()) {
184	    const colonIdx = key.indexOf(":");
185	    const provider = key.slice(0, colonIdx);
186	    const eventAction = key.slice(colonIdx + 1);
187	    console.log(`  fixtures/${provider}/${eventAction}.json`);
188	  }
189	
190	  process.exit(0);
191	}
192	
193	main().catch((err) => {
194	  console.error("Capture failed:", err);
195	  process.exit(1);
196	});
